const ICONS = {"android/app/src/main/res/mipmap-mdpi/ic_launcher_foreground.png": "", "android/app/src/main/res/mipmap-hdpi/ic_launcher_foreground.png": "", "android/app/src/main/res/mipmap-xhdpi/ic_launcher_foreground.png": "", "android/app/src/main/res/mipmap-xxhdpi/ic_launcher_foreground.png": "", "android/app/src/main/res/mipmap-xxxhdpi/ic_launcher_foreground.png": "", "android/app/src/main/res/mipmap-mdpi/ic_launcher.png": "", "android/app/src/main/res/mipmap-mdpi/ic_launcher_round.png": "", "android/app/src/main/res/mipmap-hdpi/ic_launcher.png": "", "android/app/src/main/res/mipmap-hdpi/ic_launcher_round.png": "", "android/app/src/main/res/mipmap-xhdpi/ic_launcher.png": "", "android/app/src/main/res/mipmap-xhdpi/ic_launcher_round.png": "", "android/app/src/main/res/mipmap-xxhdpi/ic_launcher.png": "", "android/app/src/main/res/mipmap-xxhdpi/ic_launcher_round.png": "", "android/app/src/main/res/mipmap-xxxhdpi/ic_launcher.png": "", "android/app/src/main/res/mipmap-xxxhdpi/ic_launcher_round.png": ""};

/* ============================================================================
 *  patch-icones.cjs  —  Trengo/Tsengo
 *  Corrige l'icône de l'APK natif (coupée / pas ronde) :
 *  régénère le foreground adaptatif (logo dans la SAFE ZONE ~60%, centré)
 *  + ic_launcher.png + ic_launcher_round.png sur toutes les densités.
 *  Le fond adaptatif reste blanc (@color/ic_launcher_background), donc
 *  l'icône s'affiche ronde et complète comme la PWA.
 *
 *  ⚠️ Effet NATIF uniquement → nécessite un rebuild APK (Actions).
 *
 *  Usage (Termux) :
 *    cp /sdcard/Download/patch-icones.cjs ~/Tsengo-fresh/
 *    cd ~/Tsengo-fresh && node patch-icones.cjs
 *    git add -A && git commit -m "Icone adaptive Trengo (safe zone)" && git push origin main
 *    Puis relance "Build Native APK".
 * ==========================================================================*/
const fs = require('fs');
const path = require('path');

let OK = 0, FAIL = 0;
(function () {
  try {
    let n = 0, miss = 0;
    for (const rel of Object.keys(ICONS)) {
      if (!fs.existsSync(path.dirname(rel))) { miss++; continue; }
      fs.writeFileSync(rel, Buffer.from(ICONS[rel], 'base64'));
      n++;
    }
    if (n > 0) { OK++; console.log('✅ icônes régénérées : ' + n + ' fichiers' + (miss ? ' (' + miss + ' dossiers absents)' : '')); }
    else { FAIL++; console.log('❌ aucun dossier mipmap trouvé'); }
  } catch (e) { FAIL++; console.log('❌ ' + e.message); }
})();

console.log('\n────────────── RÉSUMÉ ──────────────');
console.log(`✅ ${OK}   ❌ ${FAIL}`);
console.log('\nRebuild requis : git push origin main → Actions → "Build Native APK".');
console.log('Le fond reste blanc (values/ic_launcher_background.xml = #FFFFFF).');
